#include <bits/stdc++.h>
using namespace std;
int n,dp[1502][2];
bool b[1502];
vector<int> g[1502];
void dfs(int x){
    int len=g[x].size();
    b[x]=1;
    dp[x][1]=1;
    for(int i=0;i<len;i++)
        if(!b[g[x][i]]){
            dfs(g[x][i]);
            dp[x][1]+=min(dp[g[x][i]][1],dp[g[x][i]][0]);
            dp[x][0]+=dp[g[x][i]][1];
        }
}
int main(){
    cin>>n;
    for(int i=0;i<n;i++){
        int u,k;
        cin>>u>>k;
        for(int j=1;j<=k;j++){
            int v;
            cin>>v;
            g[u].push_back(v);
            g[v].push_back(u);
        }
    }
    dfs(0);
    cout<<min(dp[0][1],dp[0][0]);
    return 0;
}
